//! Qwen Scope SAE — Top-k Sparse Autoencoder architecture for ed2kIA v2.1.\n//!\n//! Feature-gated behind `v2.1-qwen-scope-sae`. Provides exact Top-k SAE\n//! implementation using candle-core tensors, compatible with WASM targets.\n//!\n//! Architecture: 4 tensors (W_enc, W_dec, b_enc, b_dec)\n//! Forward pass: `f(x) = TopK(W_enc @ (x - b_dec) + b_enc)`\n//! Returns: `(sparse_values, sparse_indices)`\n//!\n//! **Status:** Functional scaffold with exact math + unit tests.\n//! **License:** Apache 2.0 + Ethical Use Clause\n\nuse candle_core::{Device, Tensor};\nuse thiserror::Error;\n\n/// Errors specific to Qwen Scope SAE operations.\n#[derive(Debug, Error)]\npub enum QwenScopeError {\n    #[error("Tensor operation failed: {0}")]\n    TensorOp(#[from] candle_core::Error),\n\n    #[error("Invalid k value: {k} (must be 1..={max})")]\n    InvalidK { k: usize, max: usize },\n\n    #[error("Shape mismatch: expected {expected:?}, got {actual:?}")]\n    ShapeMismatch { expected: Vec<usize>, actual: Vec<usize> },\n\n    #[error("Invalid input shape: {0}")]\n    InvalidInputShape(String),\n}\n\n/// Qwen Scope SAE model with 4-tensor Top-k architecture.\n#[derive(Debug)]\npub struct QwenScopeSAE {\n    /// W_enc: [d_sae, d_model] - Encoding weight matrix\n    pub w_enc: Tensor,\n    /// W_dec: [d_model, d_sae] - Decoding weight matrix\n    pub w_dec: Tensor,\n    /// b_enc: [d_sae] - Encoding bias\n    pub b_enc: Tensor,\n    /// b_dec: [d_model] - Decoding bias (input centering)\n    pub b_dec: Tensor,\n    /// Top-k sparsity parameter\n    pub k: usize,\n}\n\nimpl QwenScopeSAE {\n    /// Create a new QwenScopeSAE from pre-computed tensors.\n    ///\n    /// # Arguments\n    /// * `w_enc` - [d_sae, d_model] encoding weights\n    /// * `w_dec` - [d_model, d_sae] decoding weights\n    /// * `b_enc` - [d_sae] encoding bias\n    /// * `b_dec` - [d_model] decoding bias\n    /// * `k` - Number of top activations to preserve\n    ///\n    /// # Returns\n    /// `Ok(QwenScopeSAE)` on success, or error if shapes are inconsistent\n    pub fn new(\n        w_enc: Tensor,\n        w_dec: Tensor,\n        b_enc: Tensor,\n        b_dec: Tensor,\n        k: usize,\n    ) -> Result<Self, QwenScopeError> {\n        // Validate shapes\n        let w_enc_shape = w_enc.shape().dims().to_vec();\n        let w_dec_shape = w_dec.shape().dims().to_vec();\n        let b_enc_shape = b_enc.shape().dims().to_vec();\n        let b_dec_shape = b_dec.shape().dims().to_vec();\n\n        // W_enc: [d_sae, d_model]\n        if w_enc_shape.len() != 2 {\n            return Err(QwenScopeError::InvalidInputShape(\n                format!("W_enc must be 2D, got {:?}", w_enc_shape),\n            ));\n        }\n        let d_sae = w_enc_shape[0];\n        let d_model = w_enc_shape[1];\n\n        // W_dec: [d_model, d_sae]\n        if w_dec_shape != [d_model, d_sae] {\n            return Err(QwenScopeError::ShapeMismatch {\n                expected: vec![d_model, d_sae],\n                actual: w_dec_shape,\n            });\n        }\n\n        // b_enc: [d_sae]\n        if b_enc_shape != [d_sae] {\n            return Err(QwenScopeError::ShapeMismatch {\n                expected: vec![d_sae],\n                actual: b_enc_shape,\n            });\n        }\n\n        // b_dec: [d_model]\n        if b_dec_shape != [d_model] {\n            return Err(QwenScopeError::ShapeMismatch {\n                expected: vec![d_model],\n                actual: b_dec_shape,\n            });\n        }\n\n        // Validate k\n        if k == 0 || k >= d_sae {\n            return Err(QwenScopeError::InvalidK { k, max: d_sae - 1 });\n        }\n\n        Ok(Self {\n            w_enc,\n            w_dec,\n            b_enc,\n            b_dec,\n            k,\n        })\n    }\n\n    /// Execute forward pass: `f(x) = TopK(W_enc @ (x - b_dec) + b_enc)`\n    ///\n    /// # Arguments\n    /// * `x` - Input tensor [batch_size, d_model] or [d_model]\n    ///\n    /// # Returns\n    /// `(sparse_values, sparse_indices)` where:\n    /// - `sparse_values`: [batch_size, k] activated values\n    /// - `sparse_indices`: [batch_size, k] activated neuron indices\n    pub fn forward(&self, x: &Tensor) -> Result<(Tensor, Tensor), QwenScopeError> {\n        let input_shape = x.shape().dims().to_vec();\n\n        // Handle 1D input by expanding to 2D\n        let (x_2d, expanded) = if input_shape.len() == 1 {\n            let x_2d = x.unsqueeze(0)?;\n            (x_2d, true)\n        } else {\n            (x.clone(), false)\n        };\n\n        // Step 1: Center input: x_centered = x - b_dec\n        let x_centered = (&x_2d - &self.b_dec)?;\n\n        // Step 2: Encode: encoded = W_enc @ x_centered + b_enc\n        let encoded = self.w_enc.matmul(&x_centered)?;\n        let encoded = (encoded + &self.b_enc)?;\n\n        // Step 3: Top-k selection\n        let (top_values, top_indices) = self.topk(&encoded)?;\n\n        // If input was 1D, squeeze output back\n        let (top_values, top_indices) = if expanded {\n            (top_values.squeeze(0)?, top_indices.squeeze(0)?)\n        } else {\n            (top_values, top_indices)\n        };\n\n        Ok((top_values, top_indices))\n    }\n\n    /// Execute full decode: `x_reconstructed = W_dec @ sparse_activations + b_dec`\n    ///\n    /// # Arguments\n    /// * `sparse_values` - [batch_size, k] top-k values\n    /// * `sparse_indices` - [batch_size, k] top-k indices\n    ///\n    /// # Returns\n    /// Reconstructed tensor [batch_size, d_model]\n    pub fn decode(&self, sparse_values: &Tensor, sparse_indices: &Tensor) -> Result<Tensor, QwenScopeError> {\n        // Create sparse activation tensor from indices and values\n        let batch_size = sparse_values.shape().dims()[0];\n        let k = sparse_values.shape().dims()[1];\n        let d_sae = self.w_enc.shape().dims()[0];\n        let device = self.w_dec.device();\n\n        // Create zero tensor [batch_size, d_sae]\n        let mut sparse_activations = Tensor::zeros((batch_size, d_sae), candle_core::DType::F32, device)?;\n\n        // Scatter values into positions\n        // Note: This is a simplified scatter; production may use candle_ops\n        let values_data = sparse_values.to_vec2::<f32>()?;\n        let indices_data = sparse_indices.to_vec2::<usize>()?;\n\n        for batch in 0..batch_size {\n            for ki in 0..k {\n                let idx = indices_data[batch][ki];\n                let val = values_data[batch][ki];\n                sparse_activations.set(&[batch, idx], val)?;\n            }\n        }\n\n        // Decode: x_reconstructed = W_dec @ sparse_activations + b_dec\n        let reconstructed = self.w_dec.matmul(&sparse_activations)?;\n        let reconstructed = (reconstructed + &self.b_dec)?;\n\n        Ok(reconstructed)\n    }\n\n    /// Efficient Top-k implementation using candle-core operations.\n    ///\n    /// For WASM compatibility, uses sort-based approach that works\n    /// without CUDA-specific kernels.\n    fn topk(&self, encoded: &Tensor) -> Result<(Tensor, Tensor), QwenScopeError> {\n        let dtype = encoded.dtype();\n        let device = encoded.device();\n        let shape = encoded.shape().dims().to_vec();\n\n        // Handle both 1D and 2D cases\n        let (encoded_2d, expanded) = if shape.len() == 1 {\n            (encoded.unsqueeze(0)?, true)\n        } else {\n            (encoded.clone(), false)\n        };\n\n        let dims_2d = encoded_2d.shape().dims().to_vec();\n        let batch_size = dims_2d[0];\n        let d_sae = dims_2d[1];\n\n        // Get absolute values for top-k selection (neurons fire on magnitude)\n        let abs_encoded = encoded_2d.abs()?;\n\n        // Flatten to [batch_size, d_sae] for processing\n        let flat_data = abs_encoded.to_vec2::<f32>()?;\n\n        // Build top-k values and indices per batch\n        let mut top_values = Vec::with_capacity(batch_size * self.k);\n        let mut top_indices = Vec::with_capacity(batch_size * self.k);\n\n        for batch in 0..batch_size {\n            // Create indexed values for this batch\n            let mut indexed: Vec<(f32, usize)> = flat_data[batch]\n                .iter()\n                .enumerate()\n                .map(|(idx, val)| (*val, idx))\n                .collect();\n\n            // Partial sort to get top-k (more efficient than full sort)\n            indexed.select_nth_unstable_by(self.k, |a, b| b.0.partial_cmp(&a.0).unwrap());\n\n            // Take top-k\n            for item in indexed.iter().take(self.k) {\n                // Use original (signed) value from encoded tensor\n                let orig_data = encoded_2d.to_vec2::<f32>()?;\n                top_values.push(orig_data[batch][item.1]);\n                top_indices.push(item.1);\n            }\n        }\n\n        // Create output tensors [batch_size, k]\n        let top_values_tensor = Tensor::from_vec(\n            top_values,\n            (batch_size, self.k),\n            device,\n        )?;\n        let top_indices_tensor = Tensor::from_vec(\n            top_indices,\n            (batch_size, self.k),\n            device,\n        )?;\n\n        // Squeeze if input was 1D\n        let (top_values_tensor, top_indices_tensor) = if expanded {\n            (top_values_tensor.squeeze(0)?, top_indices_tensor.squeeze(0)?)\n        } else {\n            (top_values_tensor, top_indices_tensor)\n        };\n\n        Ok((top_values_tensor, top_indices_tensor))\n    }\n\n    /// Get the d_sae (latent dimension) of this SAE.\n    pub fn d_sae(&self) -> usize {\n        self.w_enc.shape().dims()[0]\n    }\n\n    /// Get the d_model (input dimension) of this SAE.\n    pub fn d_model(&self) -> usize {\n        self.w_enc.shape().dims()[1]\n    }\n\n    /// Estimate memory usage in MB for this SAE.\n    pub fn estimate_memory_mb(&self) -> usize {\n        let bytes_per_elem = 4; // f32\n        let total_elems = self.w_enc.shape().size()\n            + self.w_dec.shape().size()\n            + self.b_enc.shape().size()\n            + self.b_dec.shape().size();\n        total_elems * bytes_per_elem / (1024 * 1024)\n    }\n}\n\n#[cfg(test)]\nmod tests {\n    use super::*;\n\n    fn create_test_sae(d_model: usize, d_sae: usize, k: usize) -> Result<QwenScopeSAE, QwenScopeError> {\n        let device = Device::Cpu;\n        // W_enc: [d_sae, d_model]\n        let w_enc = Tensor::rand(0.0, 1.0, (d_sae, d_model), &device)\n            .map_err(|e| QwenScopeError::TensorOp(e))?;\n        // W_dec: [d_model, d_sae]\n        let w_dec = Tensor::rand(0.0, 1.0, (d_model, d_sae), &device)\n            .map_err(|e| QwenScopeError::TensorOp(e))?;\n        // b_enc: [d_sae]\n        let b_enc = Tensor::zeros(d_sae, candle_core::DType::F32, &device)\n            .map_err(|e| QwenScopeError::TensorOp(e))?;\n        // b_dec: [d_model]\n        let b_dec = Tensor::zeros(d_model, candle_core::DType::F32, &device)\n            .map_err(|e| QwenScopeError::TensorOp(e))?;\n\n        QwenScopeSAE::new(w_enc, w_dec, b_enc, b_dec, k)\n    }\n\n    #[test]\n    fn test_sae_creation() -> Result<(), QwenScopeError> {\n        let sae = create_test_sae(256, 1024, 10)?;\n        assert_eq!(sae.d_model(), 256);\n        assert_eq!(sae.d_sae(), 1024);\n        assert_eq!(sae.k, 10);\n        Ok(())\n    }\n\n    #[test]\n    fn test_sae_invalid_k_zero() {\n        let device = Device::Cpu;\n        let w_enc = Tensor::rand(0.0, 1.0, (10, 5), &device).unwrap();\n        let w_dec = Tensor::rand(0.0, 1.0, (5, 10), &device).unwrap();\n        let b_enc = Tensor::zeros(10, candle_core::DType::F32, &device).unwrap();\n        let b_dec = Tensor::zeros(5, candle_core::DType::F32, &device).unwrap();\n\n        let result = QwenScopeSAE::new(w_enc, w_dec, b_enc, b_dec, 0);\n        assert!(result.is_err());\n    }\n\n    #[test]\n    fn test_sae_invalid_k_too_large() {\n        let device = Device::Cpu;\n        let w_enc = Tensor::rand(0.0, 1.0, (10, 5), &device).unwrap();\n        let w_dec = Tensor::rand(0.0, 1.0, (5, 10), &device).unwrap();\n        let b_enc = Tensor::zeros(10, candle_core::DType::F32, &device).unwrap();\n        let b_dec = Tensor::zeros(5, candle_core::DType::F32, &device).unwrap();\n\n        let result = QwenScopeSAE::new(w_enc, w_dec, b_enc, b_dec, 10);\n        assert!(result.is_err());\n    }\n\n    #[test]\n    fn test_sae_invalid_w_dec_shape() {\n        let device = Device::Cpu;\n        let w_enc = Tensor::rand(0.0, 1.0, (10, 5), &device).unwrap();\n        let w_dec = Tensor::rand(0.0, 1.0, (5, 8), &device).unwrap(); // Wrong shape\n        let b_enc = Tensor::zeros(10, candle_core::DType::F32, &device).unwrap();\n        let b_dec = Tensor::zeros(5, candle_core::DType::F32, &device).unwrap();\n\n        let result = QwenScopeSAE::new(w_enc, w_dec, b_enc, b_dec, 3);\n        assert!(result.is_err());\n    }\n\n    #[test]\n    fn test_forward_pass_2d() -> Result<(), QwenScopeError> {\n        let sae = create_test_sae(64, 256, 8)?;\n        let x = Tensor::rand(0.0, 1.0, (2, 64), &Device::Cpu)\n            .map_err(|e| QwenScopeError::TensorOp(e))?;\n\n        let (values, indices) = sae.forward(&x)?;\n        assert_eq!(values.shape().dims()[0], 2); // batch_size\n        assert_eq!(values.shape().dims()[1], 8); // k\n        assert_eq!(indices.shape().dims()[0], 2);\n        assert_eq!(indices.shape().dims()[1], 8);\n        Ok(())\n    }\n\n    #[test]\n    fn test_forward_pass_1d() -> Result<(), QwenScopeError> {\n        let sae = create_test_sae(64, 256, 8)?;\n        let x = Tensor::rand(0.0, 1.0, 64, &Device::Cpu)\n            .map_err(|e| QwenScopeError::TensorOp(e))?;\n\n        let (values, indices) = sae.forward(&x)?;\n        assert_eq!(values.shape().dims()[0], 8); // k\n        assert_eq!(indices.shape().dims()[0], 8);\n        Ok(())\n    }\n\n    #[test]\n    fn test_topk_returns_correct_count() -> Result<(), QwenScopeError> {\n        let sae = create_test_sae(32, 128, 5)?;\n        let x = Tensor::rand(0.0, 1.0, (4, 32), &Device::Cpu)\n            .map_err(|e| QwenScopeError::TensorOp(e))?;\n\n        let (values, indices) = sae.forward(&x)?;\n        assert_eq!(values.shape().dims(), [4, 5]);\n        assert_eq!(indices.shape().dims(), [4, 5]);\n        Ok(())\n    }\n\n    #[test]\n    fn test_decode() -> Result<(), QwenScopeError> {\n        let sae = create_test_sae(64, 256, 8)?;\n        let x = Tensor::rand(0.0, 1.0, (2, 64), &Device::Cpu)\n            .map_err(|e| QwenScopeError::TensorOp(e))?;\n\n        let (values, indices) = sae.forward(&x)?;\n        let reconstructed = sae.decode(&values, &indices)?;\n        assert_eq!(reconstructed.shape().dims(), [2, 64]);\n        Ok(())\n    }\n\n    #[test]\n    fn test_estimate_memory_mb() -> Result<(), QwenScopeError> {\n        let sae = create_test_sae(256, 1024, 10)?;\n        let mem_mb = sae.estimate_memory_mb();\n        // W_enc: 1024*256*4 = 1MB, W_dec: 256*1024*4 = 1MB, biases negligible\n        assert!(mem_mb >= 1 && mem_mb <= 5);\n        Ok(())\n    }\n\n    #[test]\n    fn test_error_display() {\n        let err = QwenScopeError::InvalidK { k: 0, max: 10 };\n        assert!(!format!("{}", err).is_empty());\n\n        let err = QwenScopeError::ShapeMismatch {\n            expected: vec![10],\n            actual: vec![5],\n        };\n        assert!(!format!("{}", err).is_empty());\n    }\n}\n
